import React from "react";

export const CtaBanner = (props) => {
  const d = props.data;
  if (!d) return null;
  return (
    <section id="cta" className="55lab-cta">
      <div className="container">
        <h2>{d.title}</h2>
        <a
          href={d.buttonHref}
          className="btn btn-lg btn-55lab-primary page-scroll"
        >
          {d.buttonLabel}
        </a>
      </div>
    </section>
  );
};
